snips.body:
interfaces {
    $LAG_FXC {
        flexible-vlan-tagging;
        mtu 9102;
        encapsulation flexible-ethernet-services;
        esi {
            $FXC_ESI;
            single-active;
            df-election-granularity {
                per-esi {
                    lacp-oos-on-ndf;
                }
            }
        }
        aggregated-ether-options {
            lacp {
                active;
                periodic fast;
                system-id $LACP_SYSID_FXC;
            }
        }
        unit $FXC_VLAN_UNIT {
            encapsulation vlan-ccc;
            vlan-id $FXC_VLAN_UNIT;
            family ccc;
        }
    }
    $LAG_PERSUB {
        flexible-vlan-tagging;
        mtu 9102;
        encapsulation flexible-ethernet-services;
        aggregated-ether-options {
            lacp {
                active;
                periodic fast;
                system-id $LACP_SYSID_PERSUB;
            }
        }
        unit $PERSUB_VLAN_UNIT {
            encapsulation vlan-ccc;
            vlan-id $PERSUB_VLAN_UNIT;
            esi {
                $PERSUB_ESI_VALUE;
                all-active;
            }
            family ccc;
        }
    }
}

interfaces {
    $CORE_PHYS {
        description $CORE_DESC;
        unit 0 {
            family inet {
                address $CORE_V4;
            }
            family iso;
            family inet6 {
                address $CORE_V6;
            }
            family mpls {
                maximum-labels 16;
            }
        }
    }
}

policy-options {
    prefix-list PL-AN-REGION {
        $PL_AN_REGION_LIST;
    }
    prefix-list PL-CORE {
        $PL_CORE_LIST;
    }
    policy-statement PS-BGP-RR-EXPORT {
        term CORE-NHS {
            from {
                prefix-list PL-CORE;
            }
            then {
                next-hop self;
                accept;
            }
        }
    }
    policy-statement PS-CLIENT-RR-EXPORT {
        term LOOPBACKS {
            from {
                prefix-list PL-AN-REGION;
            }
            then accept;
        }
    }
}

policy-options {
    community PPPOE_SUBS_COMM_1 members target:20000:1031;
    community PPPOE_SUBS_COMM_2 members target:20000:1032;
    community PS-DHCPSUBS-COMM members target:65000:1131;
    community PS-DHCPSUBS-COMM_2 members target:65000:1132;
    community PS-Internet-COMM members target:100:1;
    community PS-RADIUS-COMM members target:11111:1111;
}

policy-options {
    policy-statement PS-ISIS-EXPORT {
        term OOB-MGMT {
            from interface [ em0.0 fxp0.0 re0:mgmt-0.0 ];
            then reject;
        }
        term LOCAL-LOOPBACK-IPV4 {
            from {
                protocol direct;
                interface lo0.0;
                route-filter $LOOPBACK_V4/32 exact;
            }
            then {
                prefix-segment {
                    index $NODE_SID_V4;
                    node-segment;
                }
                accept;
            }
        }
        term LOCAL-LOOPBACK-IPV6 {
            from {
                protocol direct;
                interface lo0.0;
                route-filter $LOOPBACK_V6/128 exact;
            }
            then {
                prefix-segment {
                    index $NODE_SID_V6;
                    node-segment;
                }
                accept;
            }
        }
    }
}

policy-options {
    policy-statement PS-PPLB {
        then {
            load-balance per-packet;
            accept;
        }
    }
}

policy-options {
    policy-statement VRF_Internet_export {
        term 1 {
            from {
                route-filter 0.0.0.0/0 exact;
            }
            then {
                community add PS-Internet-COMM;
                next-hop $LOOPBACK_V4;
                accept;
            }
        }
        term 2 {
            from {
                route-filter ::/0 exact;
            }
            then {
                community add PS-Internet-COMM;
                next-hop $LOOPBACK_V6;
                accept;
            }
        }
    }
    policy-statement VRF_Internet_import {
        term 1 {
            from community PS-Internet-COMM;
            then accept;
        }
        term 2 {
            from community PPPOE_SUBS_COMM_2;
            then accept;
        }
        term 3 {
            from community PS-DHCPSUBS-COMM_2;
            then accept;
        }
    }
    policy-statement PS-V6-default {
        term 1 {
            from {
                instance VRF_Internet;
                route-filter ::/0 exact;
            }
            then {
                community add PS-Internet-COMM;
                next-hop $LOOPBACK_V6;
                accept;
            }
        }
        term 2 {
            then reject;
        }
    }
    policy-statement stop_leak {
        term 1 {
            from level 1;
            to level 2;
            then reject;
        }
    }
}

policy-options {
    policy-statement PS-RADIUS-VRF-EXPORT {
        term 1 {
            from protocol direct;
            then {
                community add PS-RADIUS-COMM;
                next-hop self;
                accept;
            }
        }
    }
    policy-statement PS-RADIUS-VRF-IMPORT {
        term 2 {
            from community [ PPPOE_SUBS_COMM_1 PS-DHCPSUBS-COMM ];
            then accept;
        }
        term 1 {
            from community PS-RADIUS-COMM;
            then accept;
        }
    }
    policy-statement PS-REDIS-OSPF {
        term 1 {
            from protocol bgp;
            then accept;
        }
    }
}

routing-instances {
    $INSTANCE_NAME {
        instance-type evpn-vpws;
        protocols {
            evpn {
                interface $AC_INTF {
                    vpws-service-id {
                        local $VPWS_LOCAL_ID;
                        remote $VPWS_REMOTE_ID;
                    }
                }
            }
        }
        interface $AC_INTF;
        route-distinguisher $RD_LOOPBACK_V4:$RD_ID;
        vrf-target target:$RT_AS:$RT_ID;
    }
}

routing-instances {
    $INSTANCE_NAME {
        instance-type evpn-vpws;
        protocols {
            evpn {
                label-allocation per-instance;
                flexible-cross-connect-vlan-unaware;
                group fxc {
                    esi {
                        $FXC_ESI;
                    }
                    interface $AC1;
                    interface $AC2;
                    service-id {
                        local $SVC_LOCAL;
                        remote $SVC_REMOTE;
                    }
                }
            }
        }
        interface $AC1;
        interface $AC2;
        route-distinguisher $RD_LOOPBACK_V4:$RD_ID;
        vrf-target target:$RT_AS:$RT_ID;
    }
}

routing-instances {
    VRF_Internet {
        instance-type vrf;
        routing-options {
            rib VRF_Internet.inet6.0 {
                static {
                    route ::/0 discard;
                }
            }
            static {
                route 0.0.0.0/0 discard;
            }
        }
        protocols {
            bgp {
                group CE1 {
                    type external;
                    accept-remote-nexthop;
                    family inet {
                        unicast;
                    }
                    neighbor $CE_PEER_V4 {
                        family inet {
                            unicast;
                        }
                        peer-as $CE_AS_V4;
                    }
                    neighbor $CE_PEER_V6 {
                        family inet6 {
                            unicast;
                        }
                        peer-as $CE_AS_V6;
                    }
                }
            }
        }
        interface $CE_INTF;
        route-distinguisher $RD_LOOPBACK_V4:$RD_ID;
        vrf-import VRF_Internet_import;
        vrf-export VRF_Internet_export;
        vrf-table-label;
    }
}

routing-instances {
    RADIUS {
        instance-type vrf;
        protocols {
            ospf {
                area 0.0.0.0 {
                    interface $RADIUS_INTF;
                }
                export PS-REDIS-OSPF;
            }
        }
        interface $RADIUS_INTF;
        interface $LO_UNIT;
        route-distinguisher $RD_LOOPBACK_V4:$RD_ID;
        vrf-import PS-RADIUS-VRF-IMPORT;
        vrf-export PS-RADIUS-VRF-EXPORT;
        vrf-target target:$RT_AS:$RT_ID;
        vrf-table-label;
    }
}

protocols {
    bgp {
        group GR-IBGP-AN {
            type internal;
            local-address $LOOPBACK_V4;
            family inet {
                labeled-unicast {
                    rib {
                        inet.3;
                    }
                }
            }
            family inet6 {
                labeled-unicast {
                    rib {
                        inet6.3;
                    }
                }
            }
            family evpn {
                signaling;
            }
            bfd-liveness-detection {
                minimum-interval 100;
                multiplier 3;
            }
            neighbor $RR_AGN1_V4;
            neighbor $RR_AGN2_V4;
        }
    }
}

protocols {
    bgp {
        advertise-from-main-vpn-tables;
        vpn-apply-export;
        group GR-IBGP-CORE-RR {
            type internal;
            accept-remote-nexthop;
            local-address $LOOPBACK_V4;
            family inet {
                labeled-unicast {
                    rib {
                        inet.3;
                    }
                }
            }
            family inet-vpn {
                unicast;
            }
            family inet6 {
                labeled-unicast {
                    rib {
                        inet6.3;
                    }
                }
            }
            family inet6-vpn {
                unicast;
            }
            family evpn {
                signaling;
            }
            export PS-BGP-RR-EXPORT;
            cluster $LOOPBACK_V4;
            bfd-liveness-detection {
                minimum-interval 100;
                multiplier 3;
            }
            neighbor $AGN1_V4;
            neighbor $AGN2_V4;
            neighbor $BNG1_V4;
            neighbor $BNG2_V4;
        }
        group GR-IBGP-CR {
            type internal;
            accept-remote-nexthop;
            local-address $LOOPBACK_V4;
            family inet {
                labeled-unicast {
                    rib {
                        inet.3;
                    }
                }
            }
            family inet-vpn {
                unicast;
            }
            family inet6 {
                labeled-unicast {
                    rib {
                        inet6.3;
                    }
                }
            }
            family inet6-vpn {
                unicast;
            }
            family evpn {
                signaling;
            }
            export PS-CLIENT-RR-EXPORT;
            cluster $LOOPBACK_V4;
            bfd-liveness-detection {
                minimum-interval 100;
                multiplier 3;
            }
            neighbor $BNG3_V4;
            neighbor $BNG4_V4;
        }
    }
}

protocols {
    bgp {
        advertise-from-main-vpn-tables;
        vpn-apply-export;
        group GR-IBGP-FABRIC-RR {
            type internal;
            local-address $LOOPBACK_V4;
            family inet {
                labeled-unicast {
                    rib {
                        inet.3;
                    }
                }
            }
            family inet6 {
                labeled-unicast {
                    rib {
                        inet6.3;
                    }
                }
            }
            family evpn {
                signaling;
            }
            cluster $LOOPBACK_V4;
            bfd-liveness-detection {
                minimum-interval 100;
                multiplier 3;
            }
            neighbor $AN1_V4;
            neighbor $AN2_V4;
            neighbor $AN3_V4;
            neighbor $AN4_V4;
            neighbor $AN5_V4;
        }
        group GR-IBGP-CR {
            type internal;
            local-address $LOOPBACK_V4;
            family inet {
                labeled-unicast {
                    rib {
                        inet.3;
                    }
                }
            }
            family inet6 {
                labeled-unicast {
                    rib {
                        inet6.3;
                    }
                }
            }
            family evpn {
                signaling;
            }
            cluster $LOOPBACK_V4;
            bfd-liveness-detection {
                minimum-interval 100;
                multiplier 3;
            }
            neighbor $BNG1_V4;
            neighbor $BNG2_V4;
            neighbor $CR_V4;
        }
    }
}

protocols {
    isis {
        interface $CORE_INTF {
            level $ISIS_LEVEL {
                post-convergence-lfa {
                    node-protection cost 16777214;
                }
            }
            point-to-point;
            family inet {
                bfd-liveness-detection {
                    minimum-interval 100;
                    multiplier 3;
                    no-adaptation;
                }
            }
        }
        interface lo0.0 {
            passive;
        }
        source-packet-routing explicit-null;
        level 1 wide-metrics-only;
        level 2 $L2_KNOB;
        spf-options {
            microloop-avoidance {
                post-convergence-path {
                    delay 5000;
                }
            }
            multipath {
                weighted one-hop;
            }
        }
        backup-spf-options {
            use-post-convergence-lfa maximum-labels 5;
            use-source-packet-routing;
        }
        traffic-engineering {
            l3-unicast-topology;
            advertisement always;
        }
        export $EXPORT_POLICY;
    }
}

protocols {
    mpls {
        label-range {
            srgb-label-range $SRGB_START $SRGB_END;
        }
        ipv6-tunneling;
    }
}

routing-options {
    router-id $ROUTER_ID;
    autonomous-system $LOCAL_AS;
    forwarding-table {
        export PS-PPLB;
        chained-composite-next-hop {
            ingress {
                evpn;
            }
        }
    }
}

chassis {
    maximum-ecmp 128;
    redundancy {
        graceful-switchover;
    }
    pseudowire-service {
        device-count $PS_DEVICE_COUNT;
    }
    fpc $TS_FPC {
        pic $TS_PIC {
            tunnel-services {
                bandwidth $TS_BW;
            }
        }
    }
}

firewall {
    family inet {
        filter clear-df-bit {
            interface-specific;
            term 1 {
                then {
                    accept;
                    dont-fragment clear;
                }
            }
        }
        filter rpf-pass-dhcp {
            term allow-dhcp {
                from {
                    destination-address {
                        255.255.255.255/32;
                    }
                    destination-port dhcp;
                }
                then accept;
            }
            term default {
                then {
                    discard;
                }
            }
        }
    }
    family inet6 {
        filter rpf-pass-dhcpv6 {
            term allow-dhcpv6 {
                from {
                    destination-address {
                        ffff::ffff/128;
                    }
                    destination-port dhcp;
                }
                then accept;
            }
            term default {
                then discard;
            }
        }
    }
}

interfaces {
    $LAG {
        flexible-vlan-tagging;
        mtu 9102;
        encapsulation flexible-ethernet-services;
        aggregated-ether-options {
            lacp {
                active;
                periodic fast;
            }
        }
        unit $LAG_VLAN_UNIT {
            encapsulation vlan-bridge;
            vlan-id $LAG_VLAN_ID;
        }
    }
    $CPE_PORT {
        flexible-vlan-tagging;
        encapsulation flexible-ethernet-services;
        unit $LAG_VLAN_UNIT {
            encapsulation vlan-bridge;
            vlan-id $LAG_VLAN_ID;
        }
    }
}
vlans {
    $BD_NAME {
        vlan-id $LAG_VLAN_ID;
        interface $CPE_PORT.$LAG_VLAN_UNIT;
        interface $LAG.$LAG_VLAN_UNIT;
    }
}

interfaces {
    $CORE_PHYS {
        description $CORE_DESC;
        unit 0 {
            family inet {
                address $CORE_V4;
            }
            family iso;
            family inet6 {
                address $CORE_V6;
            }
            family mpls {
                maximum-labels 16;
            }
        }
    }
}

interfaces {
    $PS_DEV {
        anchor-point {
            $ANCHOR_LT;
        }
        flexible-vlan-tagging;
        auto-configure {
            stacked-vlan-ranges {
                dynamic-profile $DYN_PROFILE {
                    accept any;
                    ranges {
                        any,any;
                    }
                }
                authentication {
                    packet-types any;
                    password $USER_PASS;
                    username-include {
                        domain-name $DOMAIN_NAME;
                        user-prefix $USER_PREFIX;
                    }
                }
                access-profile $AUTH_PROFILE;
            }
            remove-when-no-subscribers;
        }
        mtu $MTU;
        esi {
            $ESI_VALUE;
            single-active;
            df-election-type {
                preference {
                    value $DF_PREFERENCE;
                }
            }
        }
        mac $STATIC_MAC;
        no-gratuitous-arp-request;
        unit 0 {
            encapsulation ethernet-ccc;
        }
    }
}

interfaces {
    $PS_DEV {
        anchor-point {
            $ANCHOR_LT;
        }
        flexible-vlan-tagging;
        auto-configure {
            stacked-vlan-ranges {
                dynamic-profile $DYN_PROFILE {
                    accept [ pppoe inet inet6 ];
                    ranges {
                        any,any;
                    }
                }
                authentication {
                    packet-types [ pppoe any ];
                    password $USER_PASS;
                    username-include {
                        domain-name $DOMAIN_NAME;
                        user-prefix $USER_PREFIX;
                    }
                }
                access-profile $AUTH_PROFILE;
            }
            remove-when-no-subscribers;
        }
        mtu $MTU;
        esi {
            $ESI_VALUE;
            single-active;
            df-election-type {
                preference {
                    value $DF_PREFERENCE;
                }
            }
        }
        no-gratuitous-arp-request;
        unit 0 {
            encapsulation ethernet-ccc;
        }
    }
}

policy-options {
    community PPPOE_SUBS_COMM_1 members target:20000:1031;
    community PPPOE_SUBS_COMM_2 members target:20000:1032;
    community PS-DHCPSUBS-COMM members target:65000:1131;
    community PS-DHCPSUBS-COMM_2 members target:65000:1132;
    community PS-Internet-COMM members target:100:1;
    community PS-RADIUS-COMM members target:11111:1111;
}

policy-options {
    policy-statement PS-ISIS-EXPORT {
        term OOB-MGMT {
            from interface [ em0.0 fxp0.0 re0:mgmt-0.0 ];
            then reject;
        }
        term LOCAL-LOOPBACK-IPV4 {
            from {
                protocol direct;
                interface lo0.0;
                route-filter $LOOPBACK_V4/32 exact;
            }
            then {
                prefix-segment {
                    index $NODE_SID_V4;
                    node-segment;
                }
                accept;
            }
        }
        term LOCAL-LOOPBACK-IPV6 {
            from {
                protocol direct;
                interface lo0.0;
                route-filter $LOOPBACK_V6/128 exact;
            }
            then {
                prefix-segment {
                    index $NODE_SID_V6;
                    node-segment;
                }
                accept;
            }
        }
    }
}

policy-options {
    policy-statement PS-PPLB {
        then {
            load-balance per-packet;
            accept;
        }
    }
}

policy-options {
    policy-statement PS-PPPOE-SUBS-1-VRF-EXPORT {
        term 1 {
            from protocol direct;
            then {
                community add PPPOE_SUBS_COMM_1;
                next-hop self;
                accept;
            }
        }
        term 2 {
            from {
                protocol aggregate;
                route-filter 10.25.0.0/16 exact;
            }
            then {
                community add PPPOE_SUBS_COMM_2;
                next-hop self;
                accept;
            }
        }
        term 3 {
            from {
                protocol aggregate;
                route-filter fc00:25:140::/48 exact;
            }
            then {
                community add PPPOE_SUBS_COMM_2;
                next-hop self;
                accept;
            }
        }
    }
    policy-statement PS-PPPOE-SUBS-1-VRF-IMPORT {
        term 1 {
            from community PS-RADIUS-COMM;
            then accept;
        }
        term 2 {
            from community PS-Internet-COMM;
            then accept;
        }
    }
    policy-statement PS-PPPOE-SUBSv6 {
        term 1 {
            from {
                instance PPPOE_SUBS_1;
                route-filter fc00:25:140::/48 exact;
            }
            then {
                community add PPPOE_SUBS_COMM_2;
                next-hop $LOOPBACK_V6;
                accept;
            }
        }
    }
    policy-statement dhcp-subs-vrf-export-pol {
        term 1 {
            from protocol direct;
            then {
                community add PS-DHCPSUBS-COMM;
                next-hop self;
                accept;
            }
        }
        term 2 {
            from protocol access-internal;
            then {
                community add PS-DHCPSUBS-COMM_2;
                next-hop self;
                accept;
            }
        }
    }
    policy-statement dhcp-subs-vrf-import-pol {
        term 1 {
            from community PS-RADIUS-COMM;
            then accept;
        }
        term 2 {
            from community PS-Internet-COMM;
            then accept;
        }
    }
    policy-statement PS-DHCP-SUBSv6 {
        term 1 {
            from {
                instance dhcp-subs;
                protocol access-internal;
            }
            then {
                community add PS-DHCPSUBS-COMM_2;
                next-hop $LOOPBACK_V6;
                accept;
            }
        }
    }
}

policy-options {
    policy-statement PS-RADIUS-VRF-EXPORT {
        term 1 {
            from protocol direct;
            then {
                community add PS-RADIUS-COMM;
                next-hop self;
                accept;
            }
        }
    }
    policy-statement PS-RADIUS-VRF-IMPORT {
        term 1 {
            from community PS-RADIUS-COMM;
            then accept;
        }
    }
}

routing-instances {
    $INSTANCE_NAME {
        instance-type evpn-vpws;
        protocols {
            evpn {
                interface $PS_AC {
                    vpws-service-id {
                        local $VPWS_LOCAL_ID;
                        remote $VPWS_REMOTE_ID;
                    }
                }
            }
        }
        interface $PS_AC;
        route-distinguisher $RD_LOOPBACK_V4:$RD_ID;
        vrf-target target:$RT_AS:$RT_ID;
    }
}

routing-instances {
    $INSTANCE_NAME {
        instance-type evpn-vpws;
        protocols {
            evpn {
                interface $PS_AC {
                    vpws-service-id {
                        local $VPWS_LOCAL_ID;
                        remote $VPWS_REMOTE_ID;
                    }
                }
            }
        }
        interface $PS_AC;
        route-distinguisher $RD_LOOPBACK_V4:$RD_ID;
        vrf-target target:$RT_AS:$RT_ID;
    }
}

routing-instances {
    $INSTANCE_NAME {
        instance-type evpn-vpws;
        protocols {
            evpn {
                interface $PS_AC {
                    vpws-service-id {
                        local $VPWS_LOCAL_ID;
                        remote $VPWS_REMOTE_ID;
                    }
                }
            }
        }
        interface $PS_AC;
        route-distinguisher $RD_LOOPBACK_V4:$RD_ID;
        vrf-target target:$RT_AS:$RT_ID;
    }
}

routing-instances {
    $VRF_NAME {
        instance-type vrf;
        routing-options {
            rib $VRF_NAME.inet6.0 {
                static {
                    route fc00:126:140::/64 discard;
                }
                aggregate {
                    route fc00:125:140::/64;
                    route fc00:126:140::/64;
                }
            }
            static {
                route 10.43.0.1/32 discard;
            }
            aggregate {
                route 10.42.0.0/16;
                route 10.43.0.0/16;
            }
            auto-export;
        }
        system {
            services {
                dhcp-local-server {
                    dhcpv6 {
                        group dhcp6-ls {
                            authentication {
                                password $USER_PASS;
                                username-include {
                                    domain-name $DOMAIN_NAME;
                                    user-prefix $USER_PREFIX;
                                }
                            }
                            dynamic-profile prod-dhcp-base;
                            overrides {
                                delegated-pool $V6_POOL;
                                dual-stack dhcp-ds;
                            }
                            interface demux0.0;
                            interface demux0.1;
                            interface ps11.0;
