                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                advertise-default;
                nexthop-resolution { no-resolution; }
            }
            export PS-VPN-SRV6;
            neighbor $RR_PEER_V6 {
                description PEER-RR;
            }
        }

        /* RR clients (PEs / Edges / MSEs) */
        group GR-IBGP-RR-CLIENTS-SRV6 {
            local-address $RR_LOCAL_V6;
            family inet {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
