                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                advertise-default;
                nexthop-resolution { no-resolution; }
            }
            cluster $RR_CLUSTER_ID;
            $CLIENT_NEIGHBOR_LIST;
        }

        /* ASBR (BR<->RR) sessions for inter-AS Option C */
        group GR-IBGP-ASBR-SRV6 {
            local-address $RR_LOCAL_V6;
            family inet {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                external-paths 3;
                nexthop-resolution { no-resolution; }
            }
            export PS-VPN-SRV6;
            cluster $RR_CLUSTER_ID;
            $ASBR_NEIGHBOR_LIST;
        }

        precision-timers;
        advertise-inactive;
        log-updown;
        bgp-error-tolerance;
        multipath {
            list-nexthop;
        }
        rfc8950-compliant;
        defaults {
            ebgp {
                no-policy {
                    receive reject-always;
                    advertise reject-always;
                }
            }
        }
    }
}

