            }
        }
        source-packet-routing {
            srv6 {
                locator $DEFAULT_SVC_LOC {
                    micro-dt46-sid;
                }
            }
        }
        precision-timers;
        advertise-inactive;
        log-updown;
        bgp-error-tolerance;
        multipath {
            list-nexthop;
        }
        rfc8950-compliant;
    }
}

protocols {
    bgp {
        apply-groups GR-BGP;
        path-selection external-router-id;
        advertise-from-main-vpn-tables;
        vpn-apply-export;

        /* RR<->RR full mesh */
        group GR-IBGP-RRS-SRV6 {
            local-address $RR_LOCAL_V6;
            family inet {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                advertise-default;
                nexthop-resolution { no-resolution; }
            }
            export PS-VPN-SRV6;
            neighbor $RR_PEER_V6 {
                description PEER-RR;
            }
        }

        /* RR clients (PEs / Edges / MSEs) */
        group GR-IBGP-RR-CLIENTS-SRV6 {
            local-address $RR_LOCAL_V6;
            family inet {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                advertise-default;
                nexthop-resolution { no-resolution; }
            }
            cluster $RR_CLUSTER_ID;
            $CLIENT_NEIGHBOR_LIST;
        }

        /* ASBR (BR<->RR) sessions for inter-AS Option C */
        group GR-IBGP-ASBR-SRV6 {
            local-address $RR_LOCAL_V6;
            family inet {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    nexthop-resolution { no-resolution; }
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    nexthop-resolution { no-resolution; }
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family route-target {
                external-paths 3;
                nexthop-resolution { no-resolution; }
            }
            export PS-VPN-SRV6;
            cluster $RR_CLUSTER_ID;
            $ASBR_NEIGHBOR_LIST;
        }

        precision-timers;
        advertise-inactive;
        log-updown;
        bgp-error-tolerance;
        multipath {
            list-nexthop;
        }
        rfc8950-compliant;
        defaults {
            ebgp {
                no-policy {
                    receive reject-always;
                    advertise reject-always;
                }
            }
        }
    }
}

routing-options {
    transport-class {
        auto-create;
        name TC-128 { color 128; }
        name TC-129 { color 129; }
        name TC-131 { color 131; }
        name TC-132 { color 132; }
        name TC-133 { color 133; }
    }
    flex-algorithm 131 {
        use-transport-class {
            inet3-install;
        }
    }
    flex-algorithm 132 {
        use-transport-class {
            inet3-install;
        }
    }
    flex-algorithm 133 {
        use-transport-class {
            inet3-install;
        }
    }
}

protocols {
    bgp {
        group GR-EBGP-INTER-AS-OPTION-C {
            type external;
            multihop ttl $EBGP_MULTIHOP_TTL;
            local-address $LOCAL_BR_V6_LOOPBACK;
            family inet {
                unicast {
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet-vpn {
                unicast {
                    extended-nexthop;
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6 {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family inet6-vpn {
                unicast {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            family evpn {
                signaling {
                    advertise-srv6-service;
                    accept-srv6-service;
                }
            }
            authentication-algorithm ao;
            authentication-key-chain KC-EBGP;
            export PS-INTER-AS-EXPORT;
            import PS-INTER-AS-IMPORT;
            peer-as $REMOTE_AS;
            local-as $LOCAL_AS;
            neighbor $REMOTE_BR_V6_LOOPBACK {
                description PEER-BR;
            }
        }
    }
}

routing-options {
    flex-algorithm 128 {
        definition {
            metric-type delay-metric;
        }
        use-transport-class {
            inet3-install;
        }
    }
    flex-algorithm 129 {
        definition {
            metric-type te-metric;
        }
        use-transport-class {
            inet3-install;
        }
    }
    source-packet-routing {
        srv6 {
            apply-groups GR-SRV6;
            block $LOC_BLOCK_FA_0 {
                $LOC_BLOCK_PREFIX_0;
                local-micro-sid {
                    maximum-static-sids $LOCAL_USID_LIMIT;
                }
            }
            block $LOC_BLOCK_FA_128 {
                $LOC_BLOCK_PREFIX_128;
                local-micro-sid {
                    maximum-static-sids $LOCAL_USID_LIMIT;
                }
            }
            block $LOC_BLOCK_FA_129 {
                $LOC_BLOCK_PREFIX_129;
                local-micro-sid {
                    maximum-static-sids $LOCAL_USID_LIMIT;
                }
            }
            locator $LOC_FA_0 {
                $LOC_PREFIX_0;
                micro-sid {
                    block-name $LOC_BLOCK_FA_0;
                }
            }
            locator $LOC_FA_128 {
                algorithm 128;
                $LOC_PREFIX_128;
                micro-sid {
                    block-name $LOC_BLOCK_FA_128;
                }
            }
            locator $LOC_FA_129 {
                algorithm 129;
                $LOC_PREFIX_129;
                micro-sid {
                    block-name $LOC_BLOCK_FA_129;
                }
            }
        }
    }
    route-distinguisher-id $RD_ID;
    rib inet.3 {
        protect core;
    }
    resolution {
        preserve-nexthop-hierarchy;
    }
    router-id $ROUTER_ID;
    autonomous-system $LOCAL_AS;
    ipv6-router-id $IPV6_ROUTER_ID;
    protect core;
    forwarding-table {
        srv6-chain-merge;
        export PS-LOAD-BALANCE;
    }
}
protocols {
    isis {
        apply-groups GR-ISIS-IPV6;
        /* Repeat one `interface <ifl>;` per core IFL */
        interface $ISIS_IFL_LIST;
        interface lo0.0 {
            passive;
        }
        source-packet-routing {
            flex-algorithm $FA_LIST;
            no-strict-spf;
            srv6 {
                locator $LOC_FA_0 micro-node-sid;
                locator $LOC_FA_128 micro-node-sid;
                locator $LOC_FA_129 micro-node-sid;
            }
        }
        level 1 disable;
        level 2 {
            purge-originator empty;
            wide-metrics-only;
        }
        backup-spf-options {
            use-post-convergence-lfa maximum-backup-paths 2;
            use-source-packet-routing;
        }
        traffic-engineering {
            l3-unicast-topology;
            tunnel-source-protocol {
                spring-te;
            }
            advertisement always;
        }
        reference-bandwidth $REF_BANDWIDTH;
        max-hello-size $JUMBO_HELLO_SIZE;
        suppress-attached-bit;
        no-external-export {
            protocol bgp;
            protocol ospf;
            protocol static;
        }
        topologies ipv6-unicast;
        overload {
            timeout $OVERLOAD_TIMEOUT;
            advertise-high-metrics;
            internal-prefixes;
            external-prefixes;
        }
        net $ISIS_NET;
    }
}

protocols {
    isis {
        export PS-SRV6-LOC-EXPORT;
    }
    bgp {
        group GR-IBGP-ASBR-SRV6 {
            export PS-SRV6-LOC-EXPORT;
        }
    }
}
policy-options {
    policy-statement PS-SRV6-LOC-EXPORT {
        term TR-SUM-FA-0 {
            from {
                route-filter $SUMMARY_PREFIX_FA_0 exact;
            }
            then accept;
        }
        term TR-SUM-FA-128 {
            from {
                route-filter $SUMMARY_PREFIX_FA_128 exact;
            }
            then accept;
        }
        term TR-SUM-FA-129 {
            from {
                route-filter $SUMMARY_PREFIX_FA_129 exact;
            }
            then accept;
        }
    }
}

protocols {
    isis {
        backup-spf-options {
            use-post-convergence-lfa maximum-backup-paths $MAX_BACKUP_PATHS;
            use-source-packet-routing;
        }
        inactive: spf-options {
            microloop-avoidance {
                post-convergence-path {
                    delay $MLA_DELAY;
                }
            }
            delay 50;
            holddown 2000;
            rapid-runs 5;
        }
    }
}
